import { getCategories } from "@/lib/content"
import { getSearchIndex } from "@/lib/search"
import { DocsSidebar } from "@/components/docs-sidebar"
import { MobileSidebar } from "@/components/mobile-sidebar"
import { SearchDialog } from "@/components/search-dialog"
import "./helpbase-styles.css"

export default async function DocsLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const [categories, searchItems] = await Promise.all([
    getCategories(),
    getSearchIndex(),
  ])

  return (
    <>
      <div className="mx-auto max-w-7xl">
        <div className="flex">
          {/* Desktop sidebar */}
          <aside className="hidden w-60 shrink-0 lg:block">
            <div className="sticky top-14 h-[calc(100svh-3.5rem)] overflow-y-auto border-r border-border/50 px-4 py-8">
              <DocsSidebar categories={categories} />
            </div>
          </aside>

          {/* Mobile sidebar trigger */}
          <div className="lg:hidden">
            <MobileSidebar categories={categories} />
          </div>

          {/* Main content */}
          <div className="min-w-0 flex-1">{children}</div>
        </div>
      </div>

      {/* Cmd+K search — mounts invisibly, opens on keyboard shortcut */}
      <SearchDialog items={searchItems} />
    </>
  )
}

import Link from "next/link"
import { notFound } from "next/navigation"
import { getCategories } from "@/lib/content"

export async function generateStaticParams() {
  const categories = await getCategories()
  return categories.map((c) => ({ category: c.slug }))
}

export default async function CategoryPage({
  params,
}: {
  params: Promise<{ category: string }>
}) {
  const { category: categorySlug } = await params
  const categories = await getCategories()
  const category = categories.find((c) => c.slug === categorySlug)

  if (!category) notFound()

  return (
    <div className="max-w-5xl px-8 py-10 lg:px-12">
      {/* Breadcrumb */}
      <nav className="mb-6 flex items-center gap-1.5 text-sm text-muted-foreground">
        <Link href="/docs" className="transition-colors hover:text-foreground">
          Docs
        </Link>
        <ChevronIcon />
        <span className="text-foreground">{category.title}</span>
      </nav>

      {/* Header */}
      <div className="mb-10">
        <h1 className="text-3xl font-bold tracking-tight">
          {category.title}
        </h1>
        {category.description && (
          <p className="mt-2 text-lg text-muted-foreground">
            {category.description}
          </p>
        )}
      </div>

      {/* Articles */}
      {category.articles.length > 0 ? (
        <div className="grid gap-2">
          {category.articles.map((article) => (
            <Link
              key={article.slug}
              href={`/${categorySlug}/${article.slug}`}
              className="group flex items-center gap-4 rounded-xl border border-transparent px-4 py-4 transition-[border-color,background-color] duration-150 ease-out hover:border-border hover:bg-muted/30"
            >
              <div className="flex size-8 shrink-0 items-center justify-center rounded-lg bg-muted transition-colors group-hover:bg-foreground group-hover:text-background">
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="size-4">
                  <path d="M15 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7Z" />
                  <path d="M14 2v4a2 2 0 0 0 2 2h4" />
                </svg>
              </div>
              <div className="min-w-0 flex-1">
                <h2 className="font-medium leading-snug">{article.title}</h2>
                <p className="mt-0.5 line-clamp-1 text-sm text-muted-foreground">
                  {article.description}
                </p>
              </div>
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="size-4 shrink-0 text-muted-foreground/50 transition-transform group-hover:translate-x-0.5 group-hover:text-foreground">
                <path d="m9 18 6-6-6-6" />
              </svg>
            </Link>
          ))}
        </div>
      ) : (
        <div className="rounded-xl border border-dashed border-border px-6 py-16 text-center text-muted-foreground">
          <p>No articles in this category yet.</p>
        </div>
      )}
    </div>
  )
}

function ChevronIcon() {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="size-3.5">
      <path d="m9 18 6-6-6-6" />
    </svg>
  )
}

import Link from "next/link"
import { notFound } from "next/navigation"
import {
  getAllArticles,
  getArticle,
  getAdjacentArticles,
} from "@/lib/content"
import { resolveAssetPath } from "@/lib/assets"
import { titleCase } from "@/lib/slugify"
import { Badge } from "@/components/ui/badge"
import { TableOfContents } from "@/components/toc"

export async function generateStaticParams() {
  const articles = await getAllArticles()
  return articles.map((a) => ({
    category: a.category,
    slug: a.slug,
  }))
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ category: string; slug: string }>
}) {
  const { category, slug } = await params
  const article = await getArticle(category, slug)
  if (!article) return {}

  return {
    title: article.title,
    description: article.description,
  }
}

export default async function ArticlePage({
  params,
}: {
  params: Promise<{ category: string; slug: string }>
}) {
  const { category, slug } = await params
  const article = await getArticle(category, slug)

  if (!article) notFound()

  const { prev, next } = await getAdjacentArticles(category, slug)

  return (
    <div className="flex">
      {/* Main content area */}
      <div className="min-w-0 flex-1 px-8 py-10 lg:px-12 xl:max-w-4xl">
        {/* Breadcrumb */}
        <nav className="mb-6 flex items-center gap-1.5 text-sm text-muted-foreground">
          <Link href="/docs" className="transition-colors hover:text-foreground">
            Docs
          </Link>
          <ChevronIcon />
          <Link
            href={`/${category}`}
            className="transition-colors hover:text-foreground"
          >
            {titleCase(category)}
          </Link>
          <ChevronIcon />
          <span className="truncate text-foreground">{article.title}</span>
        </nav>

        <article>
          <header className="mb-10">
            <h1 className="text-3xl font-bold tracking-tight">
              {article.title}
            </h1>
            <p className="mt-3 text-lg leading-relaxed text-muted-foreground">
              {article.description}
            </p>
            {article.tags.length > 0 && (
              <div className="mt-4 flex flex-wrap gap-2">
                {article.tags.map((tag) => (
                  <Badge key={tag} variant="secondary">
                    {tag}
                  </Badge>
                ))}
              </div>
            )}
            <a
              href={`https://github.com/Codehagen/helpbase/edit/main/apps/web/${article.filePath}`}
              target="_blank"
              rel="noopener noreferrer"
              className="mt-4 inline-flex items-center gap-1.5 text-xs text-muted-foreground transition-colors hover:text-foreground"
            >
              <PencilIcon />
              Edit on GitHub
            </a>
          </header>

          {/* Hero image — between description and article body */}
          {article.heroImage && (
            <div className="mb-8 max-h-[360px] overflow-hidden rounded-xl border border-border">
              <img
                src={resolveAssetPath(article.category, article.slug, article.heroImage)}
                alt={article.title}
                loading="eager"
                className="w-full object-cover"
              />
            </div>
          )}
          {/* Video embed fallback when no hero image */}
          {article.videoEmbed && !article.heroImage && (
            <div className="relative mb-8 aspect-video overflow-hidden rounded-xl border border-border">
              <iframe
                src={article.videoEmbed}
                title={`Video: ${article.title}`}
                sandbox="allow-scripts allow-same-origin"
                referrerPolicy="no-referrer"
                allow="fullscreen"
                className="size-full"
              />
            </div>
          )}

          {/* MDX content */}
          <div className="article-content max-w-none">
            {article.content}
          </div>

          {/* Prev/Next navigation */}
          <div className="mt-16 grid grid-cols-2 gap-4 border-t border-border pt-8">
            {prev ? (
              <Link
                href={`/${prev.category}/${prev.slug}`}
                className="group flex flex-col gap-1 rounded-xl border border-border p-4 transition-[border-color,background-color] duration-150 ease-out hover:border-foreground/15 hover:bg-muted/30"
              >
                <span className="text-xs text-muted-foreground">Previous</span>
                <span className="text-sm font-medium group-hover:text-foreground">
                  {prev.title}
                </span>
              </Link>
            ) : (
              <div />
            )}
            {next ? (
              <Link
                href={`/${next.category}/${next.slug}`}
                className="group flex flex-col items-end gap-1 rounded-xl border border-border p-4 text-right transition-[border-color,background-color] duration-150 ease-out hover:border-foreground/15 hover:bg-muted/30"
              >
                <span className="text-xs text-muted-foreground">Next</span>
                <span className="text-sm font-medium group-hover:text-foreground">
                  {next.title}
                </span>
              </Link>
            ) : (
              <div />
            )}
          </div>
        </article>
      </div>

      {/* TOC sidebar */}
      {article.toc.length > 0 && (
        <aside className="hidden w-52 shrink-0 xl:block">
          <div className="sticky top-14 h-[calc(100svh-3.5rem)] overflow-y-auto px-4 py-10">
            <h4 className="mb-4 pl-3 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
              On this page
            </h4>
            <TableOfContents items={article.toc} />
          </div>
        </aside>
      )}
    </div>
  )
}

function PencilIcon() {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="size-3">
      <path d="M21.174 6.812a1 1 0 0 0-3.986-3.987L3.842 16.174a2 2 0 0 0-.5.83l-1.321 4.352a.5.5 0 0 0 .623.622l4.353-1.32a2 2 0 0 0 .83-.497z" />
    </svg>
  )
}

function ChevronIcon() {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="size-3.5">
      <path d="m9 18 6-6-6-6" />
    </svg>
  )
}

/* helpbase styles — loaded by app/(docs)/layout.tsx.
 * CSS variables themselves come in via the cssVars field in the registry
 * item. This file carries the non-variable rules: keyframes, animations,
 * the .article-content typography used by MDX rendering, and the
 * prefers-reduced-motion escape hatch.
 */

/* Custom easing tokens (Emil Kowalski's animations.dev methodology) */
:root {
  --ease-out-quad: cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --ease-out-cubic: cubic-bezier(0.215, 0.61, 0.355, 1);
  --ease-out-quart: cubic-bezier(0.165, 0.84, 0.44, 1);
  --ease-in-out-quad: cubic-bezier(0.455, 0.03, 0.515, 0.955);
}

/* Animations */
@keyframes fade-in {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes scale-fade-in {
  from {
    opacity: 0;
    transform: scale(0.98);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

.animate-fade-in {
  will-change: transform, opacity;
  animation: fade-in 0.4s var(--ease-out-quad) both;
}

.animate-fade-in-delay-1 {
  will-change: transform, opacity;
  animation: fade-in 0.4s var(--ease-out-quad) 0.1s both;
}

.animate-fade-in-delay-2 {
  will-change: transform, opacity;
  animation: fade-in 0.4s var(--ease-out-quad) 0.2s both;
}

.animate-scale-fade-in {
  will-change: transform, opacity;
  animation: scale-fade-in 0.2s var(--ease-out-quad) both;
}

/* TOC sliding indicator —
 * ease-in-out: element already on screen moving to new position.
 * transform + opacity only: GPU-accelerated, no layout thrash.
 */
.toc-indicator {
  will-change: transform, opacity;
  transition:
    transform 0.2s var(--ease-in-out-quad),
    height 0.2s var(--ease-in-out-quad),
    opacity 0.15s ease;
}

/* Accessibility: disable all animations for users who prefer reduced motion */
@media (prefers-reduced-motion: reduce) {
  .animate-fade-in,
  .animate-fade-in-delay-1,
  .animate-fade-in-delay-2,
  .animate-scale-fade-in {
    animation: none;
  }

  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

/* Article content typography — consumed by the MDX page renderer */
.article-content {
  line-height: 1.75;
  color: var(--foreground);
}

.article-content h1 {
  font-size: 2.25rem;
  font-weight: 700;
  letter-spacing: -0.025em;
  margin-top: 2.5rem;
  margin-bottom: 1rem;
  scroll-margin-top: 5rem;
}

.article-content h2 {
  font-size: 1.5rem;
  font-weight: 600;
  letter-spacing: -0.025em;
  margin-top: 2.5rem;
  margin-bottom: 0.75rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--border);
  scroll-margin-top: 5rem;
}

.article-content h3 {
  font-size: 1.25rem;
  font-weight: 600;
  letter-spacing: -0.015em;
  margin-top: 2rem;
  margin-bottom: 0.5rem;
  scroll-margin-top: 5rem;
}

.article-content p {
  margin-top: 0;
  margin-bottom: 1.25rem;
  line-height: 1.75;
}

.article-content a {
  color: var(--foreground);
  font-weight: 500;
  text-decoration: underline;
  text-underline-offset: 4px;
  text-decoration-color: var(--border);
  transition: text-decoration-color 0.15s;
}

.article-content a:hover {
  text-decoration-color: var(--foreground);
}

.article-content strong {
  font-weight: 600;
}

.article-content ul,
.article-content ol {
  margin-top: 0;
  margin-bottom: 1.25rem;
  padding-left: 1.5rem;
}

.article-content li {
  margin-bottom: 0.375rem;
}

.article-content ul > li {
  list-style-type: disc;
}

.article-content ol > li {
  list-style-type: decimal;
}

.article-content code {
  font-family: var(--font-mono), ui-monospace, monospace;
  font-size: 0.875em;
  background: var(--muted);
  border-radius: 0.375rem;
  padding: 0.125rem 0.375rem;
}

.article-content pre {
  margin-top: 0;
  margin-bottom: 1.5rem;
  padding: 1rem 1.25rem;
  border-radius: 0.75rem;
  border: 1px solid var(--border);
  background: var(--muted);
  overflow-x: auto;
  font-size: 0.875rem;
  line-height: 1.7;
}

.article-content pre code {
  background: transparent;
  border-radius: 0;
  padding: 0;
  font-size: inherit;
}

.article-content blockquote {
  margin-top: 0;
  margin-bottom: 1.25rem;
  padding-left: 1rem;
  border-left: 3px solid var(--border);
  color: var(--muted-foreground);
  font-style: italic;
}

.article-content hr {
  margin: 2rem 0;
  border: none;
  border-top: 1px solid var(--border);
}

.article-content img {
  border-radius: 0.75rem;
  border: 1px solid var(--border);
  margin-top: 0.5rem;
  margin-bottom: 1.5rem;
}

.article-content table {
  width: 100%;
  margin-bottom: 1.5rem;
  border-collapse: collapse;
  font-size: 0.875rem;
}

.article-content th {
  text-align: left;
  font-weight: 600;
  padding: 0.5rem 0.75rem;
  border-bottom: 2px solid var(--border);
}

.article-content td {
  padding: 0.5rem 0.75rem;
  border-bottom: 1px solid var(--border);
}

.article-content tr:last-child td {
  border-bottom: none;
}

"use client"

import Link from "next/link"
import { useTheme } from "next-themes"
import { useEffect, useState } from "react"

function SearchTrigger() {
  return (
    <button
      type="button"
      className="group flex h-9 w-full max-w-sm items-center gap-2 rounded-lg border border-border bg-muted/40 px-3 text-sm text-muted-foreground transition-[border-color,background-color] duration-150 ease hover:border-foreground/20 hover:bg-muted/60 sm:w-64"
      onClick={() => {
        window.dispatchEvent(
          new KeyboardEvent("keydown", {
            key: "k",
            metaKey: true,
            bubbles: true,
          })
        )
      }}
    >
      <SearchIcon className="size-4 shrink-0 opacity-50" />
      <span className="flex-1 text-left">Search articles...</span>
      <kbd className="pointer-events-none hidden h-5 items-center gap-0.5 rounded border border-border bg-background px-1.5 font-mono text-[10px] font-medium text-muted-foreground sm:flex">
        <span className="text-xs">&#8984;</span>K
      </kbd>
    </button>
  )
}

function ThemeToggle() {
  const { resolvedTheme, setTheme } = useTheme()
  const [mounted, setMounted] = useState(false)

  useEffect(() => setMounted(true), [])

  return (
    <button
      type="button"
      onClick={() => setTheme(resolvedTheme === "dark" ? "light" : "dark")}
      className="inline-flex size-9 items-center justify-center rounded-lg text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
      aria-label="Toggle theme"
    >
      {mounted ? (
        resolvedTheme === "dark" ? (
          <SunIcon className="size-4" />
        ) : (
          <MoonIcon className="size-4" />
        )
      ) : (
        <div className="size-4" />
      )}
    </button>
  )
}

function SearchIcon({ className }: { className?: string }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
    >
      <circle cx="11" cy="11" r="8" />
      <path d="m21 21-4.3-4.3" />
    </svg>
  )
}

function SunIcon({ className }: { className?: string }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
    >
      <circle cx="12" cy="12" r="4" />
      <path d="M12 2v2" />
      <path d="M12 20v2" />
      <path d="m4.93 4.93 1.41 1.41" />
      <path d="m17.66 17.66 1.41 1.41" />
      <path d="M2 12h2" />
      <path d="M20 12h2" />
      <path d="m6.34 17.66-1.41 1.41" />
      <path d="m19.07 4.93-1.41 1.41" />
    </svg>
  )
}

function MoonIcon({ className }: { className?: string }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
    >
      <path d="M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z" />
    </svg>
  )
}

