export function Header() {
  return (
    <header className="sticky top-0 z-50 w-full border-b border-border/50 bg-background/80 backdrop-blur-lg">
      <div className="mx-auto flex h-14 max-w-6xl items-center gap-4 px-6">
        {/* Logo */}
        <Link href="/docs" className="font-semibold tracking-tight">
          helpbase
        </Link>

        {/* Search */}
        <div className="flex flex-1 justify-center px-4">
          <SearchTrigger />
        </div>

        {/* Right side */}
        <div className="flex items-center gap-1">
          <ThemeToggle />
          <a
            href="https://github.com/Codehagen/helpbase"
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex size-9 items-center justify-center rounded-lg text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
            aria-label="GitHub"
          >
            <GitHubIcon className="size-4" />
          </a>
        </div>
      </div>
    </header>
  )
}

"use client"

import { useState } from "react"
import Link from "next/link"
import { usePathname } from "next/navigation"
import { cn } from "@/lib/utils"
import type { Category } from "@/lib/types"

interface DocsSidebarProps {
  categories: Category[]
}

export function DocsSidebar({ categories }: DocsSidebarProps) {
  const pathname = usePathname()

  return (
    <nav className="space-y-1">
      {categories.map((category, index) => (
        <SidebarSection
          key={category.slug}
          category={category}
          pathname={pathname}
          isLast={index === categories.length - 1}
        />
      ))}
    </nav>
  )
}

function SidebarSection({
  category,
  pathname,
  isLast,
}: {
  category: Category
  pathname: string
  isLast: boolean
}) {
  const isCategoryActive = pathname.startsWith(`/${category.slug}`)
  const [isOpen, setIsOpen] = useState<boolean>(true)

  return (
    <div className={cn(!isLast && "pb-4")}>
      {/* Category header with toggle */}
      <button
        type="button"
        onClick={() => setIsOpen((prev) => !prev)}
        className={cn(
