import * as React from "react"
import { ThemeProvider as NextThemesProvider, useTheme } from "next-themes"

function ThemeProvider({
  children,
  ...props
}: React.ComponentProps<typeof NextThemesProvider>) {
  return (
    <NextThemesProvider
      attribute="class"
      defaultTheme="light"
      enableSystem={false}
      disableTransitionOnChange
      {...props}
    >
      <ThemeHotkey />
      {children}
    </NextThemesProvider>
  )
}

function isTypingTarget(target: EventTarget | null) {
  if (!(target instanceof HTMLElement)) {
    return false
  }

  return (
    target.isContentEditable ||
    target.tagName === "INPUT" ||
    target.tagName === "TEXTAREA" ||
    target.tagName === "SELECT"
  )
}

function ThemeHotkey() {
  const { resolvedTheme, setTheme } = useTheme()

  React.useEffect(() => {
    function onKeyDown(event: KeyboardEvent) {
      if (event.defaultPrevented || event.repeat) {
        return
      }

      if (event.metaKey || event.ctrlKey || event.altKey) {
        return
      }

      if (event.key.toLowerCase() !== "d") {
        return
      }

      if (isTypingTarget(event.target)) {
        return
      }

      setTheme(resolvedTheme === "dark" ? "light" : "dark")
    }

    window.addEventListener("keydown", onKeyDown)

    return () => {
      window.removeEventListener("keydown", onKeyDown)
    }
  }, [resolvedTheme, setTheme])

  return null
}

export { ThemeProvider }

"use client"

import { useCallback, useEffect, useRef, useState } from "react"
import { cn } from "@/lib/utils"
import type { TocItem } from "@/lib/types"

interface TableOfContentsProps {
  items: TocItem[]
}

export function TableOfContents({ items }: TableOfContentsProps) {
  const [activeId, setActiveId] = useState<string>("")
  const indicatorRef = useRef<HTMLDivElement>(null)
  const navRef = useRef<HTMLElement>(null)

  // Determine which heading is active based on scroll position.
  // Uses a "last heading above the fold" approach instead of
  // IntersectionObserver, which fixes both problems:
  //   1. Works on initial load (no scroll event needed)
  //   2. Works at page bottom (last heading wins when no heading is below)
  const updateActiveHeading = useCallback(() => {
    const headings = items
      .map((item) => ({
        id: item.id,
        el: document.getElementById(item.id),
      }))
      .filter((h) => h.el != null) as { id: string; el: HTMLElement }[]

    if (headings.length === 0) return

    // If scrolled to the bottom, activate the last heading
    const atBottom =
      window.innerHeight + window.scrollY >=
      document.documentElement.scrollHeight - 50

    if (atBottom) {
      setActiveId(headings[headings.length - 1]!.id)
      return
    }

    // Otherwise find the last heading that has scrolled past the top threshold
    const scrollY = window.scrollY + 100
    let active = headings[0]!.id

    for (const heading of headings) {
      if (heading.el.offsetTop <= scrollY) {
        active = heading.id
      } else {
        break
      }
    }

    setActiveId(active)
  }, [items])

  useEffect(() => {
    // Set initial active heading on mount
    updateActiveHeading()

    window.addEventListener("scroll", updateActiveHeading, { passive: true })
    return () => window.removeEventListener("scroll", updateActiveHeading)
  }, [updateActiveHeading])

  // Move the indicator bar using transform (GPU-accelerated)
  useEffect(() => {
    if (!activeId || !navRef.current || !indicatorRef.current) return

    const activeLink = navRef.current.querySelector(
      `[data-toc-id="${activeId}"]`
    ) as HTMLElement | null

    if (activeLink) {
      const navRect = navRef.current.getBoundingClientRect()
      const linkRect = activeLink.getBoundingClientRect()
      const y = linkRect.top - navRect.top
      indicatorRef.current.style.transform = `translateY(${y}px)`
      indicatorRef.current.style.height = `${linkRect.height}px`
      indicatorRef.current.style.opacity = "1"
    }
  }, [activeId])

  return (
    <nav ref={navRef} className="relative">
      {/* Track line */}
      <div className="absolute left-0 top-0 h-full w-px bg-border" />

      {/* Active indicator — slides along the track */}
      <div
        ref={indicatorRef}
        className="toc-indicator absolute left-0 top-0 w-px bg-foreground opacity-0"
      />

      {/* Links */}
      <div className="space-y-0.5">
        {items.map((item) => {
          const isActive = item.id === activeId
          return (
            <a
              key={item.id}
              href={`#${item.id}`}
              data-toc-id={item.id}
              className={cn(
                "block border-l border-transparent py-1 pl-3 text-[13px] leading-snug transition-colors duration-150",
                isActive
                  ? "font-medium text-foreground"
                  : "text-muted-foreground hover:text-foreground",
                item.depth === 3 && "pl-6"
              )}
            >
              {item.text}
            </a>
          )
        })}
      </div>
    </nav>
  )
}

type MDXComponents = Record<string, React.ComponentType<any>>
import { Callout } from "@/components/mdx/callout"
import { Figure } from "@/components/mdx/figure"
import { Video } from "@/components/mdx/video"
import { Steps, Step } from "@/components/mdx/steps"
import { Accordion, AccordionItem } from "@/components/mdx/accordion"
import { Tabs, Tab } from "@/components/mdx/tabs"
import { CardGroup, Card } from "@/components/mdx/card-group"
import { CtaCard } from "@/components/mdx/cta-card"

/**
 * Creates an MDX component map bound to a specific article's context.
 *
 * The category and slug are needed by Figure, Video, and CtaCard to
 * resolve relative asset paths (e.g. "hero.png" → "/_helpbase-assets/cat/slug/hero.png").
 * Without this binding, relative paths in MDX body would 404.
 *
 * The img override routes markdown images ![](path) through Figure
 * so they get the same asset resolution as <Figure src="path">.
 */
export function createArticleComponents(category: string, slug: string): MDXComponents {
  return {
    Callout,
    Figure: (props) => <Figure {...props} category={category} slug={slug} />,
    Video: (props) => <Video {...props} category={category} slug={slug} />,
    CtaCard: (props) => <CtaCard {...props} category={category} slug={slug} />,
    Steps,
    Step,
    Accordion,
    AccordionItem,
    Tabs,
    Tab,
    CardGroup,
    Card,

    // Prose overrides — route markdown images through Figure resolver
    img: (props) => (
      <Figure
        src={props.src || ""}
        alt={props.alt || ""}
        category={category}
        slug={slug}
      />
    ),

    // Enhanced table wrapper for horizontal scroll
    table: (props) => (
      <div className="my-6 overflow-x-auto rounded-lg border border-border">
        <table {...props} />
      </div>
    ),

    // The article page template already renders the article title as an <h1>
    // before the MDX body. Most authors still write `# Title` as the first
    // heading, which produces a second <h1> on the page. That duplicates
    // semantic page titles for assistive tech and surfaces in Lighthouse.
    // Downgrading body h1 to h2 preserves author intent without breaking
    // the document outline.
    h1: (props) => <h2 {...props} />,
  }
}

import path from "node:path"

export class PathTraversalError extends Error {
  constructor(assetPath: string) {
    super(
      `Path traversal rejected: "${assetPath}". ` +
        `Asset paths must be relative filenames within the article's content directory. ` +
        `Do not use "..", leading "/", backslashes, or URL schemes.`,
    )
    this.name = "PathTraversalError"
  }
}

/**
 * Resolve a relative asset path to a public URL.
 *
 * Given an article at content/<category>/<slug>.mdx and a relative asset
 * path like "hero.png", returns "/_helpbase-assets/<category>/<slug>/hero.png".
 *
 * Security: rejects path traversal attempts (.., leading /, backslash,
 * null bytes, URL schemes). This is a pure string-join after sanitization,
 * NOT a filesystem operation.
 */
export function resolveAssetPath(
  category: string,
  slug: string,
  assetPath: string,
): string {
  // Reject null bytes
  if (assetPath.includes("\0")) {
    throw new PathTraversalError(assetPath)
  }

  // Reject backslashes (Windows path separators)
  if (assetPath.includes("\\")) {
    throw new PathTraversalError(assetPath)
  }

  // Reject absolute paths
  if (assetPath.startsWith("/")) {
    throw new PathTraversalError(assetPath)
  }

  // Reject URL schemes (http://, https://, javascript:, data:, etc.)
  if (/^[a-z][a-z0-9+.-]*:/i.test(assetPath)) {
    throw new PathTraversalError(assetPath)
  }

  // Normalize and reject any traversal
  const normalized = path.posix.normalize(assetPath)
  if (normalized.startsWith("..") || normalized.startsWith("/")) {
    throw new PathTraversalError(assetPath)
  }

  // Reject if normalized path still contains ..
  if (normalized.includes("..")) {
    throw new PathTraversalError(assetPath)
  }

  return `/_helpbase-assets/${category}/${slug}/${normalized}`
}

import fs from "node:fs"
import path from "node:path"
import matter from "gray-matter"
import { compileMDX } from "next-mdx-remote/rsc"
import { cache } from "react"
import { remarkPlugins, rehypePlugins } from "./mdx-config"

import { frontmatterSchema, categoryMetaSchema } from "@/lib/schemas"
import type { ArticleMeta, Article, Category, TocItem } from "@/lib/types"
import { titleCase } from "@/lib/slugify"
import { extractToc } from "./toc"
import { createArticleComponents } from "./mdx-components"
import { resolveContentDir } from "./content-dir"

const CONTENT_DIR = resolveContentDir()

/**
 * Get all articles (frontmatter only, no compiled content).
 * Fails loudly on invalid frontmatter — never silently drops articles.
 */
export const getAllArticles = cache(async (): Promise<ArticleMeta[]> => {
  const articles: ArticleMeta[] = []
  const errors: string[] = []

  if (!fs.existsSync(CONTENT_DIR)) {
    return []
  }

  const categoryDirs = fs
    .readdirSync(CONTENT_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory())

  for (const dir of categoryDirs) {
    const categorySlug = dir.name
    const categoryPath = path.join(CONTENT_DIR, categorySlug)
    const files = fs
      .readdirSync(categoryPath)
      .filter((f) => f.endsWith(".mdx") || f.endsWith(".md"))

    for (const file of files) {
      const filePath = path.join(categoryPath, file)
      const raw = fs.readFileSync(filePath, "utf-8")
      const { data, content } = matter(raw)

      const parsed = frontmatterSchema.safeParse(data)
      if (!parsed.success) {
        errors.push(
          `${categorySlug}/${file}: ${parsed.error.issues.map((i) => i.message).join(", ")}`
        )
        continue
      }

      const slug = file.replace(/\.mdx?$/, "")
      articles.push({
        ...parsed.data,
        slug,
        category: categorySlug,
        filePath: `content/${categorySlug}/${file}`,
        rawContent: content,
      })
    }
  }

  // Fail the build on invalid articles (never silently drop content)
  if (errors.length > 0 && process.env.NODE_ENV === "production") {
    throw new Error(
      `Invalid frontmatter in ${errors.length} article(s):\n${errors.map((e) => `  - ${e}`).join("\n")}\n\nFix these issues or run 'helpcenter audit' for details.`
    )
  } else if (errors.length > 0) {
    console.warn(
      `⚠ Skipping ${errors.length} article(s) with invalid frontmatter:\n${errors.map((e) => `  - ${e}`).join("\n")}`
    )
  }

  return articles.sort((a, b) => a.order - b.order)
})

/**
 * Get all categories with their articles.
 */
export const getCategories = cache(async (): Promise<Category[]> => {
  const articles = await getAllArticles()

  if (!fs.existsSync(CONTENT_DIR)) {
    return []
  }

  const categoryDirs = fs
    .readdirSync(CONTENT_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory())

  const categories: Category[] = categoryDirs.map((dir) => {
    const slug = dir.name
    const metaPath = path.join(CONTENT_DIR, slug, "_category.json")

    let meta = { title: titleCase(slug), description: "", icon: "file-text", order: 999 }
    if (fs.existsSync(metaPath)) {
      // Two failure modes surface the same way to the docs author: a typo'd
      // _category.json silently reverts to defaults, which is confusing when
      // the title/icon they set doesn't show up. Warn loudly on both
      // (invalid JSON syntax + valid JSON that fails the schema).
      try {
        const raw = JSON.parse(fs.readFileSync(metaPath, "utf-8"))
        const parsed = categoryMetaSchema.safeParse(raw)
        if (parsed.success) {
          meta = parsed.data
        } else {
          console.warn(
            `⚠ Invalid _category.json for "${slug}": ${parsed.error.issues.map((i) => i.message).join(", ")} — using defaults`,
          )
        }
      } catch (err) {
        console.warn(
          `⚠ Could not parse _category.json for "${slug}": ${err instanceof Error ? err.message : String(err)} — using defaults`,
        )
      }
    }

    return {
      slug,
      ...meta,
      articles: articles.filter((a) => a.category === slug),
    }
  })

  return categories.sort((a, b) => a.order - b.order)
})

/**
 * Get a single article with compiled MDX content and TOC.
 */
export const getArticle = cache(
  async (category: string, slug: string): Promise<Article | null> => {
    const extensions = [".mdx", ".md"]
    let filePath: string | null = null
    let rawFile: string | null = null

    for (const ext of extensions) {
      const candidate = path.join(CONTENT_DIR, category, `${slug}${ext}`)
      if (fs.existsSync(candidate)) {
        filePath = candidate
        rawFile = fs.readFileSync(candidate, "utf-8")
        break
      }
    }

    if (!filePath || !rawFile) return null

    const { data, content: rawContent } = matter(rawFile)
    const parsed = frontmatterSchema.safeParse(data)
    if (!parsed.success) return null

    const toc = extractToc(rawContent)

    const { content } = await compileMDX({
      source: rawContent,
      components: createArticleComponents(category, slug),
      options: {
        mdxOptions: {
          remarkPlugins,
          rehypePlugins,
        },
      },
    })

    return {
      ...parsed.data,
      slug,
      category,
      filePath: `content/${category}/${slug}.mdx`,
      content,
      toc,
    }
  }
)

/**
 * Get featured articles for the homepage.
 */
export const getFeaturedArticles = cache(async (): Promise<ArticleMeta[]> => {
  const articles = await getAllArticles()
  return articles.filter((a) => a.featured).slice(0, 6)
})

/**
 * Get previous and next articles for navigation.
 */
export const getAdjacentArticles = cache(
  async (
    category: string,
    slug: string
  ): Promise<{ prev: ArticleMeta | null; next: ArticleMeta | null }> => {
    const articles = await getAllArticles()
    const categoryArticles = articles.filter((a) => a.category === category)
    const index = categoryArticles.findIndex((a) => a.slug === slug)

    return {
      prev: index > 0 ? categoryArticles[index - 1]! : null,
      next: index < categoryArticles.length - 1 ? categoryArticles[index + 1]! : null,
    }
  }
)

import path from "node:path"

/**
 * Resolve the MDX content directory the renderer reads from.
 *
 * Priority order:
 *   1. `HELPBASE_CONTENT_DIR` env var (absolute, or relative to cwd).
 *      Matches the MCP server's convention so one env var points both
 *      the human-facing renderer and the agent-facing MCP server at the
 *      same docs. Used by `helpbase preview` to render .helpbase/docs/
 *      from a different project without scaffolding files in it.
 *   2. `<cwd>/content` — the default when running a standard scaffold
 *      where content ships in-repo.
 *
 * Kept in its own file (not inlined in `content.ts`) so unit tests can
 * import it without pulling in the whole MDX + React stack.
 */
/**
 * `env` is typed as a plain record (not NodeJS.ProcessEnv) so tests can
 * pass `{}` or `{ HELPBASE_CONTENT_DIR: "..." }` without TypeScript
 * complaining about the rest of the process.env surface (NODE_ENV,
 * PATH, PWD, etc.). process.env is still compatible because it extends
 * this shape.
 */
export function resolveContentDir(
  env: Record<string, string | undefined> = process.env,
  cwd: string = process.cwd(),
): string {
  const envOverride = env.HELPBASE_CONTENT_DIR
  if (envOverride && envOverride.length > 0) {
    return path.isAbsolute(envOverride) ? envOverride : path.resolve(cwd, envOverride)
  }
  return path.join(cwd, "content")
}

import type { compileMDX } from "next-mdx-remote/rsc"
import remarkGfm from "remark-gfm"
import rehypeSlug from "rehype-slug"
import rehypePrettyCode, {
  type Options as PrettyCodeOptions,
} from "rehype-pretty-code"
import { createHighlighter, type Highlighter } from "shiki"

// Mirror the exact type compileMDX expects for its plugin lists. Pulled
// from next-mdx-remote's own signature so we don't need a direct dep on
// `unified` (where `PluggableList` canonically lives). If next-mdx-remote
// ever widens/narrows this, we follow it for free.
type MdxOptions = NonNullable<
  NonNullable<Parameters<typeof compileMDX>[0]["options"]>["mdxOptions"]
>
type PluginList = NonNullable<MdxOptions["rehypePlugins"]>

/**
 * Shared MDX pipeline config used by both the apex docs site
 * (lib/content.ts) and the hosted tenant route
 * (app/(tenant)/t/[tenant]/[...slug]/page.tsx).
 *
 * Having one source for the plugin list keeps syntax highlighting,
 * heading slugs, and GFM behavior identical across surfaces — the
 * divergence between the two pipelines is what left the tenant side
 * without prev/next + breadcrumbs for a while. Keep it consolidated.
 */

// Languages preloaded into the shared shiki highlighter. rehype-pretty-code
// otherwise lazy-loads per-fence and falls back to `defaultLang` when a
// lang isn't known, which is why ```mdx blocks were rendering as monochrome
// plaintext before QA flagged it on 2026-04-17 (ISSUE-002). Add to this
// list if new content uses a fence language that appears as plaintext.
const SHIKI_LANGS = [
  "bash",
  "shell",
  "sh",
  "zsh",
  "javascript",
  "typescript",
  "jsx",
  "tsx",
  "mdx",
  "md",
  "json",
  "jsonc",
  "yaml",
  "toml",
  "html",
  "css",
  "diff",
  "python",
  "go",
  "ruby",
  "rust",
  "sql",
  "dockerfile",
] as const

const SHIKI_THEMES = ["github-light", "github-dark-dimmed"] as const

// One shared highlighter across the process. Shiki's `createHighlighter`
// is expensive (loads WASM + every language grammar), so we cache the
// promise and reuse it for every MDX compile. Next.js RSC keeps this in
// the server runtime; each request reuses the same instance.
let highlighterPromise: Promise<Highlighter> | null = null
function getSharedHighlighter(): Promise<Highlighter> {
  if (!highlighterPromise) {
    highlighterPromise = createHighlighter({
      themes: [...SHIKI_THEMES],
      langs: [...SHIKI_LANGS],
    })
  }
  return highlighterPromise
}

export const prettyCodeOptions: PrettyCodeOptions = {
  // Dual-theme output: shiki injects inline styles keyed to a
  // data-theme attribute. `next-themes` toggles a class on <html>,
  // so we wire this to that class via CSS in globals.css (the
  // [data-theme] selector rehype-pretty-code emits is handled there).
  theme: {
    light: "github-light",
    dark: "github-dark-dimmed",
  },
  // Let shiki own the background on <pre> so colors line up with
  // tokens. Our own <pre> styling can still add padding/radius/border.
  keepBackground: true,
  // Don't crash on unknown language fences — fall back to plain text.
  defaultLang: "plaintext",
  // Skip the <span data-rehype-pretty-code-figure> wrapper on inline
  // `code` — we don't need token coloring for single-backtick code and
  // the wrapper plus figure-only CSS combined to push inline code onto
  // its own grid row with padding, which showed up as "inline `.mdx`
  // mysteriously appearing on its own indented line" in QA (ISSUE-003).
  bypassInlineCode: true,
  // Use the shared preloaded highlighter so all configured langs are
  // available synchronously at highlight time.
  getHighlighter: getSharedHighlighter,
}

export const remarkPlugins: PluginList = [remarkGfm]
export const rehypePlugins: PluginList = [
  rehypeSlug,
  [rehypePrettyCode, prettyCodeOptions],
]

