#!/usr/bin/env node

/**
 * `@helpbase/mcp` — stdio entry point.
 *
 * Spawned by an MCP client (Claude Desktop, Cursor, Zed, Windsurf, etc.)
 * Talks JSON-RPC over stdin/stdout. All logs go to stderr — writing anything
 * else to stdout corrupts the protocol stream.
 */

import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js"
import { buildServer } from "./server.js"

async function main() {
  const { server, deps } = buildServer()

  // Always log the bootstrap summary to stderr so users can see it when they
  // run the server manually for debugging, without polluting stdout.
  process.stderr.write(
    `[helpbase-mcp] Loaded ${deps.docs.length} docs across ${deps.categories.length} categories from ${deps.contentDir}\n`,
  )

  const transport = new StdioServerTransport()
  await server.connect(transport)
}

main().catch((err) => {
  const message = err instanceof Error ? err.message : String(err)
  process.stderr.write(`[helpbase-mcp] fatal: ${message}\n`)
  process.exit(1)
})

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js"
import {
  findContentDir,
  loadCategories,
  loadDocs,
  type CategoryMeta,
  type Doc,
} from "./content/loader.js"
import {
  findSkillsDir,
  loadSkills,
  type Skill,
} from "./content/skills.js"
import {
  handleSearchDocs,
  searchDocsInput,
} from "./tools/search-docs.js"
import { getDocInput, handleGetDoc } from "./tools/get-doc.js"
import { handleListDocs, listDocsInput } from "./tools/list-docs.js"
import { getSkillInput, handleGetSkill } from "./tools/get-skill.js"
import { handleListSkills, listSkillsInput } from "./tools/list-skills.js"

export interface ServerDeps {
  contentDir: string
  docs: Doc[]
  categories: CategoryMeta[]
  /** Resolved .helpbase/skills/ directory, or null when none was found. */
  skillsDir: string | null
  /** Loaded skills. Empty when no skills dir is present — not an error. */
  skills: Skill[]
}

export interface BuildServerOptions {
  name?: string
  version?: string
  /** Override the content dir. If omitted, resolves via findContentDir(). */
  contentDir?: string
  /**
   * Override the skills dir. If omitted, resolves via findSkillsDir().
   * Pass `null` to force skills-off regardless of filesystem state.
   */
  skillsDir?: string | null
}

/**
 * Build a fresh McpServer with three tools wired against a loaded content index.
 *
 * Transport-agnostic: this function does NOT connect a transport. Callers pick
 * stdio (entry point) or HTTP (v2) and connect themselves. Keeping transport
 * out of here is what makes adding HTTP in v2 a 1-file change.
 *
 * CRITICAL: never write to stdout from this file or anything it calls. Under
 * stdio transport, stdout carries the JSON-RPC stream and any stray write
 * corrupts it. Logs go to stderr via console.error (or a dedicated logger).
 */
export function buildServer(options: BuildServerOptions = {}): {
  server: McpServer
  deps: ServerDeps
} {
  const contentDir = options.contentDir ?? findContentDir()
  const docs = loadDocs(contentDir)
  const categories = loadCategories(contentDir)

  // Skills are OPTIONAL — no .helpbase/skills/ means an empty list,
  // not an error. Pass `skillsDir: null` to force skills-off.
  const skillsDir =
    options.skillsDir === null
      ? null
      : (options.skillsDir ?? findSkillsDir())
  const skills = loadSkills(skillsDir)

  const server = new McpServer({
    name: options.name ?? "helpbase-mcp",
    version: options.version ?? "0.0.1",
  })

  server.registerTool(
    "search_docs",
    {
      title: "Search docs",
      description:
        "Search Helpbase docs by keyword. Matches titles, descriptions, and body. Returns ranked list of matching doc slugs.",
      inputSchema: searchDocsInput.shape,
    },
    async (input) => handleSearchDocs(docs, input),
  )

  server.registerTool(
    "get_doc",
    {
      title: "Get doc",
      description:
        "Fetch the full MDX content of a single doc by slug. Slug format: 'category/slug' or just 'slug' (first match wins).",
      inputSchema: getDocInput.shape,
    },
    async (input) => handleGetDoc(docs, input),
  )

  server.registerTool(
    "list_docs",
    {
      title: "List docs",
      description:
        "List all available docs grouped by category. Optionally filter by a single category slug.",
      inputSchema: listDocsInput.shape,
    },
    async (input) => handleListDocs(docs, categories, input),
  )

  // Skills server: agents pull writing-style / tone / formatting rules
  // from .helpbase/skills/. Empty list when no skills are defined — no
  // error, just silence. See content/skills.ts.
  server.registerTool(
    "list_skills",
    {
      title: "List skills",
      description:
        "List writing-style, tone, and formatting rules the docs team has " +
        "published for this product. Returns an empty list if no skills " +
        "are defined in .helpbase/skills/.",
      inputSchema: listSkillsInput.shape,
    },
    async () => handleListSkills(skills),
  )

  server.registerTool(
    "get_skill",
    {
      title: "Get skill",
      description:
        "Fetch the full content of a single skill (writing-style / tone / " +
        "formatting rule) by name. Use list_skills to discover available " +
        "names.",
      inputSchema: getSkillInput.shape,
    },
    async (input) => handleGetSkill(skills, input),
  )

  return {
    server,
    deps: { contentDir, docs, categories, skillsDir, skills },
  }
}

import fs from "node:fs"
import path from "node:path"
import matter from "gray-matter"

export interface Doc {
  slug: string
  category: string
  title: string
  description: string
  filePath: string
  content: string
}

export interface CategoryMeta {
  slug: string
  title: string
  order: number
}

// More-specific candidates come first so `content/docs/` wins over a
// sibling `content/` that might hold non-doc assets (blog posts, changelog
// entries, marketing copy). `content/docs/` is a common MDX-in-subfolder
// convention for docs-only content.
const CONTENT_DIR_CANDIDATES = [
  "apps/web/content",
  "content/docs",
  "content",
]

/**
 * Find the content directory.
 *
 * Resolution order:
 *   1. HELPBASE_CONTENT_DIR env var (absolute or relative to cwd)
 *   2. Walk up from cwd trying each candidate in order:
 *      - `apps/web/content/` (monorepo shape)
 *      - `content/docs/`     (MDX-in-subfolder shape)
 *      - `content/`          (flat shape)
 *
 * Returns an absolute path. Throws if nothing is found — callers should let this
 * bubble up with a clear message rather than silently serving an empty index.
 */
export function findContentDir(startDir: string = process.cwd()): string {
  const envOverride = process.env.HELPBASE_CONTENT_DIR
  if (envOverride && envOverride.length > 0) {
    const resolved = path.isAbsolute(envOverride)
      ? envOverride
      : path.resolve(startDir, envOverride)
    if (!fs.existsSync(resolved)) {
      throw new Error(
        `HELPBASE_CONTENT_DIR points at ${resolved} but that directory does not exist.`,
      )
    }
    return resolved
  }

  let dir = path.resolve(startDir)
  const root = path.parse(dir).root
  while (true) {
    for (const candidate of CONTENT_DIR_CANDIDATES) {
      const full = path.join(dir, candidate)
      if (fs.existsSync(full) && fs.statSync(full).isDirectory()) {
        return full
      }
    }
    if (dir === root) break
    dir = path.dirname(dir)
  }

  throw new Error(
    `Could not find a content directory. Looked for ${CONTENT_DIR_CANDIDATES.join(" or ")} walking up from ${startDir}. Set HELPBASE_CONTENT_DIR to point at your docs folder.`,
  )
}

function deriveTitle(rawTitle: unknown, fallbackSlug: string): string {
  if (typeof rawTitle === "string" && rawTitle.trim().length > 0) {
    return rawTitle.trim()
  }
  return fallbackSlug
    .split("-")
    .map((w) => (w.length > 0 ? w[0]!.toUpperCase() + w.slice(1) : w))
    .join(" ")
}

function deriveDescription(rawDesc: unknown): string {
  if (typeof rawDesc === "string") return rawDesc.trim()
  return ""
}

/**
 * Load all docs from the content directory.
 *
 * Shape expected:
 *   <content-dir>/<category-slug>/<doc-slug>.mdx
 *
 * Files prefixed with `_` are skipped (convention for _category.json, etc.).
 * Only .mdx and .md files are loaded.
 */
export function loadDocs(contentDir: string): Doc[] {
  if (!fs.existsSync(contentDir)) return []

  const docs: Doc[] = []
  const categoryDirs = fs
    .readdirSync(contentDir, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .filter((d) => !d.name.startsWith("_"))

  for (const dir of categoryDirs) {
    const categorySlug = dir.name
    const categoryPath = path.join(contentDir, categorySlug)
    const files = fs
      .readdirSync(categoryPath)
      .filter((f) => !f.startsWith("_"))
      .filter((f) => f.endsWith(".mdx") || f.endsWith(".md"))

    for (const file of files) {
      const filePath = path.join(categoryPath, file)
      const slug = file.replace(/\.mdx?$/, "")

      // Skip unreadable or malformed files with a stderr warning instead of
      // crashing the server. A single bad frontmatter should not take down the
      // MCP stream. Mirrors apps/web/lib/content.ts's lenient-in-dev posture.
      let raw: string
      try {
        raw = fs.readFileSync(filePath, "utf-8")
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err)
        process.stderr.write(
          `[helpbase-mcp] Skipping ${categorySlug}/${file}: read failed (${msg})\n`,
        )
        continue
      }

      let parsed: ReturnType<typeof matter>
      try {
        parsed = matter(raw)
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err)
        process.stderr.write(
          `[helpbase-mcp] Skipping ${categorySlug}/${file}: malformed frontmatter (${msg})\n`,
        )
        continue
      }

      const { data, content } = parsed
      docs.push({
        slug,
        category: categorySlug,
        title: deriveTitle(data["title"], slug),
        description: deriveDescription(data["description"]),
        filePath: path.relative(contentDir, filePath),
        content: content.trim(),
      })
    }
  }

  docs.sort((a, b) => {
    if (a.category !== b.category) return a.category.localeCompare(b.category)
    return a.slug.localeCompare(b.slug)
  })

  return docs
}

/**
 * Load category metadata (title, order) from `_category.json` files.
 * Missing files are fine — we derive a sensible default.
 */
export function loadCategories(contentDir: string): CategoryMeta[] {
  if (!fs.existsSync(contentDir)) return []

  const categories: CategoryMeta[] = []
  const dirs = fs
    .readdirSync(contentDir, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .filter((d) => !d.name.startsWith("_"))

  for (const dir of dirs) {
    const metaPath = path.join(contentDir, dir.name, "_category.json")
    let title = deriveTitle(undefined, dir.name)
    let order = 999
    if (fs.existsSync(metaPath)) {
      try {
        const parsed = JSON.parse(fs.readFileSync(metaPath, "utf-8"))
        if (typeof parsed.title === "string") title = parsed.title
        if (typeof parsed.order === "number") order = parsed.order
      } catch {
        // Malformed _category.json — use defaults, don't fail.
      }
    }
    categories.push({ slug: dir.name, title, order })
  }

  categories.sort((a, b) => {
    if (a.order !== b.order) return a.order - b.order
    return a.slug.localeCompare(b.slug)
  })
  return categories
}

import type { Doc } from "./loader.js"

export interface SearchHit {
  doc: Doc
  score: number
}

/**
 * Very small keyword-match search. Lowercases both sides, splits the query on
 * whitespace, scores each doc by:
 *   +5 per query term in title
 *   +3 per query term in description
 *   +1 per query term in body (capped at 5 occurrences to avoid term-spam boost)
 *
 * v1 ships with this intentionally simple ranker. Semantic search is TODO-011.
 */
export function searchDocs(docs: Doc[], query: string): SearchHit[] {
  const terms = query
    .toLowerCase()
    .split(/\s+/)
    .map((t) => t.trim())
    .filter((t) => t.length > 0)

  if (terms.length === 0) return []

  const hits: SearchHit[] = []
  for (const doc of docs) {
    const title = doc.title.toLowerCase()
    const description = doc.description.toLowerCase()
    const body = doc.content.toLowerCase()
    let score = 0

    for (const term of terms) {
      if (title.includes(term)) score += 5
      if (description.includes(term)) score += 3
      const bodyMatches = countOccurrences(body, term)
      score += Math.min(bodyMatches, 5)
    }

    if (score > 0) hits.push({ doc, score })
  }

  hits.sort((a, b) => b.score - a.score)
  return hits
}

function countOccurrences(haystack: string, needle: string): number {
  if (needle.length === 0) return 0
  let count = 0
  let idx = 0
  while ((idx = haystack.indexOf(needle, idx)) !== -1) {
    count += 1
    idx += needle.length
  }
  return count
}

import { z } from "zod"
import { searchDocs } from "../content/index.js"
import type { Doc } from "../content/loader.js"

export const searchDocsInput = z.object({
  query: z.string().min(1, "query must not be empty"),
  limit: z.number().int().positive().max(50).optional(),
})

export type SearchDocsInput = z.infer<typeof searchDocsInput>

export function handleSearchDocs(docs: Doc[], input: SearchDocsInput) {
  const limit = input.limit ?? 10
  const hits = searchDocs(docs, input.query).slice(0, limit)

  if (hits.length === 0) {
    return {
      content: [
        {
          type: "text" as const,
          text: `No docs matched "${input.query}".`,
        },
      ],
    }
  }

  const lines = hits.map((hit) => {
    const d = hit.doc
    const desc = d.description ? ` — ${d.description}` : ""
    return `- [${d.category}/${d.slug}] ${d.title}${desc}`
  })

  return {
    content: [
      {
        type: "text" as const,
        text: `Found ${hits.length} doc(s):\n${lines.join("\n")}`,
      },
    ],
  }
}

import { z } from "zod"
import type { Doc } from "../content/loader.js"

export const getDocInput = z.object({
  slug: z
    .string()
    .min(1, "slug must not be empty")
    .describe("Either 'category/slug' or just 'slug' (first match wins)"),
})

export type GetDocInput = z.infer<typeof getDocInput>

export function handleGetDoc(docs: Doc[], input: GetDocInput) {
  const raw = input.slug.trim()
  const [categoryPart, slugPart] = raw.includes("/")
    ? raw.split("/", 2)
    : [undefined, raw]

  const match = docs.find((d) => {
    if (categoryPart !== undefined && slugPart !== undefined) {
      return d.category === categoryPart && d.slug === slugPart
    }
    return d.slug === slugPart
  })

  if (!match) {
    return {
      isError: true,
      content: [
        {
          type: "text" as const,
          text: `No doc found for "${raw}". Use list_docs to see available slugs.`,
        },
      ],
    }
  }

  const header = [
    `# ${match.title}`,
    match.description ? `> ${match.description}` : "",
    `Path: ${match.category}/${match.slug}`,
    "",
  ]
    .filter((l) => l.length > 0)
    .join("\n")

  return {
    content: [
      {
        type: "text" as const,
        text: `${header}\n\n${match.content}`,
      },
    ],
  }
}

import { z } from "zod"
import type { Doc, CategoryMeta } from "../content/loader.js"

export const listDocsInput = z.object({
  category: z
    .string()
    .optional()
    .describe("Filter to a single category slug. Omit to list everything."),
})

export type ListDocsInput = z.infer<typeof listDocsInput>

export function handleListDocs(
  docs: Doc[],
  categories: CategoryMeta[],
  input: ListDocsInput,
) {
  const filter = input.category?.trim()
  const visible = filter ? docs.filter((d) => d.category === filter) : docs

  if (visible.length === 0) {
    return {
      content: [
        {
          type: "text" as const,
          text: filter
            ? `No docs found in category "${filter}".`
            : "No docs available.",
        },
      ],
    }
  }

  const categoryOrder = new Map(categories.map((c, i) => [c.slug, i]))
  const categoryTitles = new Map(categories.map((c) => [c.slug, c.title]))

  const groups = new Map<string, Doc[]>()
  for (const d of visible) {
    const existing = groups.get(d.category) ?? []
    existing.push(d)
    groups.set(d.category, existing)
  }

  const sortedCats = Array.from(groups.keys()).sort((a, b) => {
    const oa = categoryOrder.get(a) ?? 999
    const ob = categoryOrder.get(b) ?? 999
    if (oa !== ob) return oa - ob
    return a.localeCompare(b)
  })

  const lines: string[] = []
  for (const cat of sortedCats) {
    const title = categoryTitles.get(cat) ?? cat
    lines.push(`## ${title}`)
    for (const doc of groups.get(cat)!) {
      const desc = doc.description ? ` — ${doc.description}` : ""
      lines.push(`- ${cat}/${doc.slug}: ${doc.title}${desc}`)
    }
    lines.push("")
  }

  return {
    content: [
      {
        type: "text" as const,
        text: lines.join("\n").trim(),
      },
    ],
  }
}

import fs from "node:fs"
import path from "node:path"
import matter from "gray-matter"

/**
 * A skill is a markdown file living under `.helpbase/skills/` in the user's
 * repo. It encodes a rule, convention, or style guide that an AI agent
 * should pull when authoring content for this product — tone/voice,
 * formatting standards, terminology, whatever the docs team wants
 * enforced.
 *
 * Served via the MCP tools `list_skills` and `get_skill`. The docs team
 * edits the files in git; downstream agents and tools read them over the
 * wire. No schema migration, no dashboard — markdown wins.
 *
 * This is v1 of the "skills server" Shadcn asked about on 2026-04-22:
 * https://x.com/shadcn/... ("interesting to see if this can also be a
 * skills server... enforcing tone, writing styles... editable by the
 * docs team... pulled by other teams").
 */
export interface Skill {
  /** Filename without the .md extension. Used as the identifier. */
  name: string
  /** Frontmatter `description`, or empty string if absent. */
  description: string
  /** Full post-frontmatter body. */
  content: string
  /** Absolute path, for diagnostics. */
  filePath: string
}

/**
 * Find the `.helpbase/skills/` directory.
 *
 * Resolution order:
 *   1. HELPBASE_SKILLS_DIR env var (absolute or relative to cwd)
 *   2. Walk up from cwd looking for `.helpbase/skills/`
 *
 * Returns `null` when no skills directory is found. Unlike findContentDir
 * (which throws), skills are OPTIONAL — a repo without skills should
 * surface an empty list, not crash the server.
 */
export function findSkillsDir(startDir: string = process.cwd()): string | null {
  const envOverride = process.env.HELPBASE_SKILLS_DIR
  if (envOverride && envOverride.length > 0) {
    const resolved = path.isAbsolute(envOverride)
      ? envOverride
      : path.resolve(startDir, envOverride)
    if (!fs.existsSync(resolved) || !fs.statSync(resolved).isDirectory()) {
      // Explicit override that doesn't exist IS an error — loud signal
      // that the user's env is misconfigured rather than silently empty.
      throw new Error(
        `HELPBASE_SKILLS_DIR points at ${resolved} but that directory does not exist.`,
      )
    }
    return resolved
  }

  let dir = path.resolve(startDir)
  const root = path.parse(dir).root
  while (true) {
    const candidate = path.join(dir, ".helpbase", "skills")
    if (fs.existsSync(candidate) && fs.statSync(candidate).isDirectory()) {
      return candidate
    }
    if (dir === root) return null
    dir = path.dirname(dir)
  }
}

/**
 * Load all skills from `.helpbase/skills/*.md`.
 *
 * Files prefixed with `_` are treated as drafts and skipped (matches the
 * content/docs convention). Only top-level `.md` files are loaded — no
 * subdirectories, no grouping. Keep the layout flat.
 *
 * Malformed frontmatter logs to stderr and skips the file rather than
 * crashing the server, mirroring loader.ts's lenient posture.
 */
export function loadSkills(skillsDir: string | null): Skill[] {
  if (!skillsDir) return []
  if (!fs.existsSync(skillsDir)) return []

  const entries = fs
    .readdirSync(skillsDir, { withFileTypes: true })
    .filter((e) => e.isFile())
    .filter((e) => !e.name.startsWith("_"))
    .filter((e) => e.name.endsWith(".md"))

  const skills: Skill[] = []
  for (const entry of entries) {
    const filePath = path.join(skillsDir, entry.name)
    const name = entry.name.replace(/\.md$/, "")

    let raw: string
    try {
      raw = fs.readFileSync(filePath, "utf-8")
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err)
      process.stderr.write(
        `[helpbase-mcp] Skipping skill ${entry.name}: read failed (${msg})\n`,
      )
      continue
    }

    let parsed: ReturnType<typeof matter>
    try {
      parsed = matter(raw)
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err)
      process.stderr.write(
        `[helpbase-mcp] Skipping skill ${entry.name}: malformed frontmatter (${msg})\n`,
      )
      continue
    }

    const description =
      typeof parsed.data["description"] === "string"
        ? String(parsed.data["description"]).trim()
        : ""

    skills.push({
      name,
      description,
      content: parsed.content.trim(),
      filePath,
    })
  }

  skills.sort((a, b) => a.name.localeCompare(b.name))
  return skills
}

import { z } from "zod"
import type { Skill } from "../content/skills.js"

export const listSkillsInput = z.object({}).describe("No inputs.")

export type ListSkillsInput = z.infer<typeof listSkillsInput>

export function handleListSkills(skills: Skill[]) {
  if (skills.length === 0) {
    return {
      content: [
        {
          type: "text" as const,
          text:
            "No skills defined. Add markdown files to .helpbase/skills/ to " +
            "define writing-style, tone, or formatting rules that agents " +
            "can pull via get_skill.",
        },
      ],
    }
  }

  const lines: string[] = ["## Skills", ""]
  for (const s of skills) {
    const desc = s.description ? ` — ${s.description}` : ""
    lines.push(`- ${s.name}${desc}`)
  }
  lines.push("", "Fetch a skill via get_skill({ name }).")

  return {
    content: [
      {
        type: "text" as const,
        text: lines.join("\n"),
      },
    ],
  }
}

import { z } from "zod"
import type { Skill } from "../content/skills.js"

export const getSkillInput = z.object({
  name: z
    .string()
    .min(1, "name must not be empty")
    .describe("Skill name (filename in .helpbase/skills/ without .md extension)."),
})

export type GetSkillInput = z.infer<typeof getSkillInput>

export function handleGetSkill(skills: Skill[], input: GetSkillInput) {
  const name = input.name.trim()
  const match = skills.find((s) => s.name === name)

  if (!match) {
    const available =
      skills.length > 0
        ? ` Available: ${skills.map((s) => s.name).join(", ")}.`
        : " No skills are currently defined."
    return {
      isError: true,
      content: [
        {
          type: "text" as const,
          text: `No skill found named "${name}".${available}`,
        },
      ],
    }
  }

  const header = [
    `# ${match.name}`,
    match.description ? `> ${match.description}` : "",
  ]
    .filter((l) => l.length > 0)
    .join("\n")

  return {
    content: [
      {
        type: "text" as const,
        text: `${header}\n\n${match.content}`,
      },
    ],
  }
}
